import{_ as e,o as r,c as t,a7 as p}from"./chunks/framework.BgApuQ2e.js";const o="/images/how-to-name-baby/Chi-chi-van-raisin.png",n="/images/how-to-name-baby/73-2525.png",s="/images/how-to-name-baby/zachary.png",m="/images/how-to-name-baby/jennifer.png",l="/images/how-to-name-baby/shirley-ashley.png",g="/images/how-to-name-baby/top-names-2012.png",h="/images/how-to-name-baby/emma.png",i="/images/how-to-name-baby/Top-weird-names.png",b="/images/how-to-name-baby/charlotte.png",w="/images/how-to-name-baby/brooke.png",c="/images/how-to-name-baby/evelyn.png",f="/images/how-to-name-baby/reagan.png",A="/images/how-to-name-baby/sofia.png",y="/images/how-to-name-baby/Paige.png",_="/images/how-to-name-baby/vowels.png",d="/images/how-to-name-baby/consonants.png",u="/images/how-to-name-baby/F-names.png",k="/images/how-to-name-baby/eri.png",q="/images/how-to-name-baby/la.png",x="/images/how-to-name-baby/CH.png",v="/images/how-to-name-baby/KR.png",z="/images/how-to-name-baby/CR.png",G="/images/how-to-name-baby/IS.png",I="/images/how-to-name-baby/roosevelt.png",S="/images/how-to-name-baby/taft.png",U="/images/how-to-name-baby/woodrow.png",j="/images/how-to-name-baby/warren.png",C="/images/how-to-name-baby/calvin.png",W="/images/how-to-name-baby/fdr.png",N="/images/how-to-name-baby/lynn.png",B="/images/how-to-name-baby/Screen-Shot-2013-12-13-at-12.23.09-AM.png",J="/images/how-to-name-baby/gender-handshake.png",T="/images/how-to-name-baby/adolph.png",P="/images/how-to-name-baby/pinit_fg_en_rect_gray_20.png",F=JSON.parse('{"title":"How to Name a Baby","description":"","frontmatter":{"title":"How to Name a Baby","titleZh":"如何给宝宝取名","date":"2013-12-11T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2013/12/how-to-name-baby.html","slug":"how-to-name-baby"},"headers":[],"relativePath":"posts/how-to-name-baby.md","filePath":"posts/how-to-name-baby.md","lastUpdated":1782886257000}'),E={name:"posts/how-to-name-baby.md"};function R(M,a,H,V,D,L){return r(),t("div",null,[...a[0]||(a[0]=[p('<h1 id="如何给宝宝取名-·-how-to-name-a-baby" tabindex="-1">如何给宝宝取名 · How to Name a Baby <a class="header-anchor" href="#如何给宝宝取名-·-how-to-name-a-baby" aria-label="Permalink to &quot;如何给宝宝取名 · How to Name a Baby&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2013/12/how-to-name-baby.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2013/12/how-to-name-baby.html</a> · 2013-12-11</p></blockquote><p>我朋友第一次生孩子的时候,那种感觉冲击力巨大。</p><p>我平常好好过着日子,然后这个念头突然砸下来——「Matt 有个<em>儿子</em>了」——整个世界瞬间天翻地覆。</p><p>三年过去,朋友们又添了六个娃,我 32 岁了,对这整件事已经麻木了不少。还是很怪。但不再<em>让人震惊</em>了。</p><p>我生活里的这个新现象带来了几种全新的体验——比如「因为朋友的小孩不喜欢你,你的感情受伤、自信心崩塌」,以及「意识到把小孩叫做『玩具』或『豆荚』并评论『它还没长脑子』这种玩笑,在小孩父母听来远没有你自己觉得那么好笑」。但也许最频繁的新体验,是发现自己不断卷入关于婴儿名字的讨论——一方面是跟即将当父母的朋友聊天并逼他们透露备选名单,另一方面是背着新手爸妈跟其他朋友讨论他们最终选的那个名字。</p><p>(注:候选名字最好绝对保密,等孩子生下来再公布——没有哪个名字能让所有人都满意,而这么私人的决定实在不该把别人的意见掺进来。而且孩子出生后你宣布名字时,不管别人心里怎么想,当着你的面都必须假装喜欢,所以你最后会觉得大家都喜欢这个名字。)</p><p><a href="https://1.bp.blogspot.com/-9PTwi-owzlk/Uqg9cbbDIZI/AAAAAAAAGqc/3G8VWTWQRcA/s1600/Chi+chi+van+raisin.png" target="_blank" rel="noreferrer"><img src="'+o+'" alt=""></a></p><p>你可能以为思考婴儿名字是我生活中的新鲜事,但其实我这辈子一直对这个话题着迷。</p><p>有一天我发现了一个超棒的网站,叫做 <a href="https://www.babynamewizard.com/" target="_blank" rel="noreferrer">The Baby Name Wizard</a>——特别是他们的 <a href="https://www.babynamewizard.com/voyager" target="_blank" rel="noreferrer">Voyager</a> 工具,你可以输入几个字母或一个完整的名字,就能看到这个名字随时间流行度变化的可视化图。我的好奇心从此被推到了全新的高度。Voyager 简直太好玩了,在我的<a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">黑暗游乐场</a>里长期租了个位置。(当然啦,<em>一旦</em>它变成了这篇文章的主题,Voyager 玩耍时间破天荒地被扔进了黑暗<em>森林</em>,那只猴子立刻就想干别的,不停地把页面点掉。不过那是另一个话题了。)</p><p>所以,基于以上种种原因,现在似乎是写一篇关于名字、流行趋势、以及准爸妈在做这个决定时需要考虑的事的好时机。</p><p>在 The Baby Name Wizard(还有<a href="https://www.ssa.gov/oact/babynames/decades/century.html" target="_blank" rel="noreferrer">政府官方名字数据库</a>)上耗了好多个小时之后,以下是我的思考(除非另外说明,主要聚焦美国)——</p><p><strong>准备取名的父母有几种选择:</strong></p><p><strong>1) 选经典款</strong></p><p><strong>例子:</strong> John、James、William、David、Mary、Sarah、Elizabeth</p><p>**好处:**不会让自己出洋相;不会以任何方式(包括在代际上)给孩子贴标签;显得有格调;和几个世纪以来的人类共享一个名字,某种意义上挺酷的。</p><p>**坏处:**有点无聊。</p><p>这类名字通常来自《圣经》,或者是某些著名王室的名字,它们超越了任何一代人——William 不是典型的老年人名字,也不是典型的年轻人名字——它就是 William。而且它们一直都很受欢迎。</p><p>但没有以前那么受欢迎了。<a href="https://www.ssa.gov/oact/babynames/decades/names1880s.html" target="_blank" rel="noreferrer">1880 年代男孩名字前 10 名</a> 和 <a href="https://www.ssa.gov/oact/babynames/decades/names1950s.html" target="_blank" rel="noreferrer">1950 年代男孩名字前 10 名</a> 有六个共同的名字:John、William、James、Robert、Charles 和 Thomas。但 <a href="https://www.ssa.gov/oact/babynames/index.html" target="_blank" rel="noreferrer">2012 年前 10 名</a> 里,来自那份名单的只剩一个——William。</p><p><strong>2)剑走偏锋</strong></p><p>**例子:**Winter、Namaste、Jameliah、Stormy、Cameo、Grudzel</p><p>**好处:**没人会怀疑你的胆量;如果孩子本身很酷,那这名字就非常酷。</p><p>**坏处:**他们这辈子在电话里得拼上 2 万亿次自己的名字;每次自我介绍都得看着别人琢磨该怎么反应;在学校会被取笑;可能会影响他们得到面试的机会;如果孩子本身不酷,整个事情就很尴尬;如果你只是一时兴起冲动决定的,那可就糟了,因为孩子得带着这名字过一辈子。</p><p>尽管有种种坏处,这仍是一个说「附言:我们才不在乎别人怎么想」的好机会。再说一遍,如果孩子本身很酷,一个怪名字只会让他们更酷。</p><p>不管怎样,现在选怪名字的人比以前多多了。过去的人几乎清一色都是随大流的。1950 年,只有 5% 的父母会给孩子取前 1000 名以外的名字。2012 年,27% 的父母都走了偏锋,跳出了前 1000。</p><p><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=&amp;sw=both&amp;exact=false" target="_blank" rel="noreferrer"><img src="'+n+'" alt=""></a></p><p>这是一个更大的「反从众」趋势的一部分:1880 年,男孩名字前 4 名(John、William、James、George)覆盖了每 <em>4</em> 个男孩里的 1 个。2012 年,前 4 名(Jacob、Mason、Ethan、Noah)只覆盖每 26 个男孩里的 1 个。</p><p><strong>3)稍微怪一点,但别太怪</strong></p><p>**例子:**Ashton、Wyatt、Luca、Brooklyn、Delaney、Alexia</p><p>**好处:**你在反从众,但又避开了第 2 类里的大部分坏处;如果名字真的好,别人会嫉妒,你会得意得不行;这个名字传达的信息是「我的爸妈很酷,但又没有<em>太</em>让人烦」。</p><p>**缺点:**你可能会因为自己的选择而有点太得意了——毕竟你还是让 Top 200 名单主导了你的选择;而且很有可能一大堆其他人对那个&quot;非主流&quot;的名字也是同样的感觉,结果你不知不觉就成了某个&quot;名字流行潮&quot;(Name Fad) 的一员。</p><p>这个类别非常适合那些对自己极度满意、觉得自己的孩子太特别了以至于配不上「经典名」或「Top 10 名」的父母,但同时他们又瞧不起那些取「超奇葩名」的人,觉得那些人烦人又没档次。(顺便说一句,我大部分朋友选的都是第 3 类。)</p><p>不过让我们聚焦一下我刚才在缺点里提到的东西:<em>名字流行潮</em>。原来有时候你并不是唯一爱上那个清新、美美哒名字的人,而当数百万第 3 类夫妇听说别人做出了一个绝妙的第 3 类选择时都开始说&quot;等等我也喜欢这个&quot;,一场名字流行潮就爆发了(它也可能由某个名人引发——比如过去十年里 Miley 这个名字的暴涨)。</p><p>突然间,那个完美地位于流行名单第 137 位的名字变成了第 86 位。然后第二年变成第 41 位。然后第 18 位。然后第 5 位。第 3 类夫妇全程震惊无语。</p><p>你知道那种情况吗——所有人都叫某个男生的绰号,只有他爸妈坚持用他那三个音节的全名?我觉得这里面有一部分原因就是想从一个流行烂大街的名字里硬拽出点个性来。</p><p><a href="https://3.bp.blogspot.com/-yP_WwReqKm8/UqgSVDhaDeI/AAAAAAAAGmE/p3myzkQYdV0/s1600/zachary.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt=""></a></p><p>这股流行风被另一大类父母选择进一步推高——</p><p><strong>4) 直接投身当前的蜜月期,明知自己选的是一个大众名</strong></p><p>**例子:**当前 Top 20 里的任何一个名字。</p><p>**好处:**安全;时髦;从广义上把你的孩子和整个同代人绑在一起。</p><p>**缺点:**班里还会有另外三个同名小孩,他们会被连着姓氏首字母一起称呼;你的孩子有一天会拥有一个「中年人的名字」,再后来某一天,变成一个「老年人的名字」。</p><p>对我来说,研究不同时代的名字流行潮能挖出最有意思的信息,因为它反映了整个社会在某个特定时期正在做什么。这篇文章剩下的部分,我们就来深入研究名字流行潮以及它们是怎么运作的——</p><p><strong>名字流行潮</strong></p><p>一个名字流行潮长这样:</p><p><a href="https://1.bp.blogspot.com/-zNJJkAKpuVo/Uqg1PNVBpPI/AAAAAAAAGp4/j7ZAFaRVg-0/s1600/jennifer.png" target="_blank" rel="noreferrer"><img src="'+m+'" alt=""></a></p><p>1965 到 1985 年之间,所有人都给女儿起名叫 Jennifer,而现在,没人这么起了。所以 Jennifer 正式成为一个名字流行潮。这对世界上所有的 Jennifer 们意味着什么呢?意味着虽然她们目前人生的大部分时间都享受着一个可爱、时髦、年轻的女孩名字,但她们正在通往「你妈的朋友的名字」这一终点的路上。「你妈的朋友的名字」就是那种一大堆中年人叫、而年轻人和老年人都没人叫的名字。</p><p>几十年之后,Jennifer 就可以期待拥有一个「老太太名字」(Old Lady Name) 了——所谓老太太名字,就是一大堆老太太都叫、但没有一个 75 岁以下的人叫的名字。</p><p>这倒也不见得是坏事,但事实是 Jennifer 就此被永远打上了她那代人的烙印,擦不掉了。当然,Jennifer 只是众多这类名字中的一个。</p><p>30 年后,Natalie、Chelsea、Samantha、Lindsay 这些名字听起来就会像今天的 Nancy、Cheryl、Susan、Linda 一样。再过 60 年,Ethan、Cody、Brandon、Matthew 就会变成 Earl、Chester、Bernard、Melvin。它们全都只是「名字潮流」——唯一的区别只是发生在什么年代。</p><p><a href="https://4.bp.blogspot.com/-qjQV3gpWKcA/UqgluMHNwcI/AAAAAAAAGno/uyPNr3qg07E/s1600/shirley-ashley.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt=""></a></p><p>想知道你的名字是不是一阵潮流,把它输入 <a href="https://www.babynamewizard.com/voyager" target="_blank" rel="noreferrer">Voyager</a>(不是顶上橙色框里的搜索栏——是下面写着「Baby Name &gt;」的那个)。如果图形长得像女巫的帽子,那就是潮流。</p><p><strong>那么现在什么名字最火?</strong></p><p><a href="https://www.babynamewizard.com/the-top-1000-baby-names-of-2012-united-states-of-america" target="_blank" rel="noreferrer"><img src="'+g+'" alt=""></a></p><p>Sophia 和 Emma 尤其厉害,不只横扫美国,而是横扫整个西方世界。</p><p>Sophia(或 Sofia)在意大利、芬兰、丹麦、德国、俄罗斯、乌克兰、阿根廷和智利都是宝宝名字前 6。Emma 则在爱尔兰、芬兰、挪威、加拿大、丹麦、比利时、荷兰、法国、意大利、瑞士、奥地利和德国进入前 6。Emma 的走红显然还源于一波「以曾祖母命名」的浪潮——这也是人们给孩子取名的另一种方式:</p><p><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=emma&amp;sw=both&amp;exact=true" target="_blank" rel="noreferrer"><img src="'+h+'" alt=""></a></p><p>为了强调过去那些最流行的名字有多么流行:1880 年时 Mary 的流行程度是现在 Sophia 或 Emma 的<strong>六倍</strong>。</p><p>再看 2012 年其他热门名字,就更能凸显<strong>一阵潮流过去之后有多彻底地死透:</strong></p><p><a href="https://1.bp.blogspot.com/-WpCuIur1YKg/Uqg3qVmmCUI/AAAAAAAAGqM/cmo9eJNj134/s1600/Top+weird+names.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt=""></a></p><p>明确一下:Gunner 和 Gael 现在作为宝宝名字比 Phillip 或 Scott 还常见。而 Lyric、Paisley、以及带两个 n 的 Brooklynn,都比 Lindsay、Caitlin、Erica 更常见。我们离红色那批名字的潮流期还太近,所以觉得它们仍然很普通,但其实它们不过是一阵潮流。而且已经过去了。</p><p><strong>我在研究过程中还发现了另外一些奇怪的潮流:</strong></p><p>跟人口结构有关的潮流</p><p><strong>Charlotte 有一段很奇怪的历史。</strong></p><p>几十年前,Charlotte 作为南方女性的热门名字一度式微,如今又在最自由派的州卷土重来。下面这张图显示了每个州随时间变化的流行度,州从上到下依次是从最保守到最自由。</p><p><a href="https://www.babynamewizard.com/name-mapper" target="_blank" rel="noreferrer"><img src="'+b+'" alt=""></a></p><p>所以外面有一堆叫 Charlotte 的中年保守派女性和自由派小屁孩。</p><p>我唯一一次看到一个&quot;死掉的名字&quot;在不到 80 年内复活,是当它在一个完全不同的人群里流行起来的时候(Jeremiah 就是另一个例子,它在 90 年代初的西北部熄火之后,现在在南方腹地火了起来)。</p><p><strong>我们从犹他州偷了一大堆当下最火的名字。</strong></p><p>这是 Brooke 这个名字的历史:</p><p><a href="https://www.babynamewizard.com/name-mapper" target="_blank" rel="noreferrer"><img src="'+w+'" alt=""></a></p><p>犹他州在 70 年代初就自己开始用这个名字了,然后突然到了 1980 年,所有其他人都决定跟上。同样的现象也发生在 Natalie、Aubrey、Riley(男)、Jaxon、Paisley、Braxton 和 Lacey 上。(对,这些现在都是热门名字。)不知道是谁让犹他州成了&quot;取名先知州&quot;,但它显然就是。</p><h4 id="我们还从加州偷了-evelyn。" tabindex="-1">我们还从加州偷了 Evelyn。 <a class="header-anchor" href="#我们还从加州偷了-evelyn。" aria-label="Permalink to &quot;我们还从加州偷了 Evelyn。&quot;">​</a></h4><p>Evelyn 随时间的流行度</p><h4 id="" tabindex="-1"><a href="https://www.babynamewizard.com/name-mapper" target="_blank" rel="noreferrer"><img src="'+c+'" alt=""></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![](/images/how-to-name-baby/evelyn.png)](https://www.babynamewizard.com/name-mapper)&quot;">​</a></h4><h4 id="热门女孩名-reagan-是共和党人的最爱。" tabindex="-1"><strong>热门女孩名 Reagan 是共和党人的最爱。</strong> <a class="header-anchor" href="#热门女孩名-reagan-是共和党人的最爱。" aria-label="Permalink to &quot;**热门女孩名 Reagan 是共和党人的最爱。**&quot;">​</a></h4><p><a href="https://www.babynamewizard.com/name-mapper" target="_blank" rel="noreferrer"><img src="'+f+'" alt=""></a></p><p>Braxton、Brooklyn 和 Jaxon 也一样。</p><p>Sophia 最早是最富的那几个州用的,后来火到所有人都上车了。<strong>不过 Sofia 目前仍然是富州的专利:</strong></p><p><a href="https://www.babynamewizard.com/name-mapper" target="_blank" rel="noreferrer"><img src="'+A+'" alt=""></a></p><h4 id="paige-只属于北方人。" tabindex="-1"><strong>Paige 只属于北方人。</strong> <a class="header-anchor" href="#paige-只属于北方人。" aria-label="Permalink to &quot;**Paige 只属于北方人。**&quot;">​</a></h4><p>这张地图显示了 2008 年 Paige 在哪里流行。</p><p><a href="https://www.babynamewizard.com/name-mapper" target="_blank" rel="noreferrer"><img src="'+y+'" alt=""></a></p><p>Alexa、Kathleen 和 Nicole 也是同样情况。</p><p>与此同时,Victor 主要出现在西南部,Colton 在中部,Caroline 在东部,而 Adrianna 和 Dominic 则基本上被圈在新墨西哥州。</p><p>围绕特定字母或发音的潮流</p><p><strong>以元音开头的名字在当下和 100 年前都最火,而许多以辅音开头的名字在世纪中叶最风光。</strong></p><p>元音开头的名字</p><p><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=o&amp;sw=both&amp;exact=false" target="_blank" rel="noreferrer"><img src="'+_+'" alt=""></a></p><p>辅音开头的名字</p><p><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=d&amp;sw=both&amp;exact=false" target="_blank" rel="noreferrer"><img src="'+d+'" alt=""></a></p><p><strong>而 F 开头的名字是老年人的。</strong></p><p><a href="https://3.bp.blogspot.com/-IOT7ZsFHq94/UqgqZLCkF5I/AAAAAAAAGoo/3n7R0E199uo/s1600/F+names.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt=""></a></p><p><strong>以 ERI、LA 开头,以及带 CR 音的名字,都在 1970 和 80 年代经历了一波潮流。现在全都凉了。</strong></p><p><a href="https://2.bp.blogspot.com/-cwhr5FLN4dA/UqgqZwiY9GI/AAAAAAAAGos/moE_4aDog1Q/s1600/eri.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-Squ_564vDG4/UqgqaY3oY1I/AAAAAAAAGo8/KkrUFFe_8H0/s1600/la.png" target="_blank" rel="noreferrer"><img src="'+q+'" alt=""></a></p><p><a href="https://4.bp.blogspot.com/-Yc1rxLdfPfA/UqgufT7UD-I/AAAAAAAAGpU/vmR3QbpWTe4/s1600/CH.png" target="_blank" rel="noreferrer"><img src="'+x+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-NloVxMPRpHQ/UqgufCAHRpI/AAAAAAAAGpY/8b8s4-9uX5U/s1600/KR.png" target="_blank" rel="noreferrer"><img src="'+v+'" alt=""></a></p><p><a href="https://4.bp.blogspot.com/-r2tb392I9pg/UqgufB2RTCI/AAAAAAAAGpc/-O9IMZiKiGM/s1600/CR.png" target="_blank" rel="noreferrer"><img src="'+z+'" alt=""></a></p><p><strong>眼下正流行以 IS 开头的名字。</strong></p><p><a href="https://2.bp.blogspot.com/-CqoAKGpc8vI/UqgqYzFH72I/AAAAAAAAGok/X0234Ucwvi0/s1600/IS.png" target="_blank" rel="noreferrer"><img src="'+G+'" alt=""></a></p><p>以前人们爱跟风总统的名字</p><p><a href="https://1.bp.blogspot.com/-SO24E_3GcXA/Uqg__ksEBsI/AAAAAAAAGqo/xwoLIgM8a60/s1600/roosevelt.png" target="_blank" rel="noreferrer"><img src="'+I+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-reLcJ_bHLKA/UqhAAoMxUEI/AAAAAAAAGq0/KYdUdV2-CA0/s1600/taft.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-yKpWT3a72_s/UqhAA8r1D0I/AAAAAAAAGrE/zxoSy790rcw/s1600/woodrow.png" target="_blank" rel="noreferrer"><img src="'+U+'" alt=""></a></p><p><a href="https://2.bp.blogspot.com/-0AXXcWahLMc/UqhAArhGHgI/AAAAAAAAGrM/UOCR-5vWdlw/s1600/warren.png" target="_blank" rel="noreferrer"><img src="'+j+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-g7RwWYfD8Qo/Uqg__qWwHnI/AAAAAAAAGqs/Y_DxD8--9BA/s1600/calvin.png" target="_blank" rel="noreferrer"><img src="'+C+'" alt=""></a></p><p><a href="https://3.bp.blogspot.com/-mC9ket0pwHo/Uqg__qyuRII/AAAAAAAAGqw/AGbwnM3BzJA/s1600/fdr.png" target="_blank" rel="noreferrer"><img src="'+W+'" alt=""></a></p><p>性别之间互相使坏</p><p>有时候一个性别本来好好的,过着自己的日子,忽然它的一个名字就被另一个性别抢走了:</p><p><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=lynn&amp;sw=both&amp;exact=true" target="_blank" rel="noreferrer"><img src="'+N+'" alt=""></a></p><p>再来一起女性大摇大摆抢劫的案例:</p><p><a href="https://1.bp.blogspot.com/-crkiSS5HtW4/UqqahicJT6I/AAAAAAAAGro/Q2FKcZXGN90/s1600/Screen+Shot+2013-12-13+at+12.23.09+AM.png" target="_blank" rel="noreferrer"><img src="'+B+'" alt=""></a></p><p>而且当另一性别的某个名字太流行时,这一性别也会眼红。以下<em>每一个</em>名字,在过去某段时期都曾被<em>对面</em>那个性别挤进过前 1,000 名(点击名字可以查看它在异性中的使用历史)。</p><p><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=john&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">约翰 (John)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=william&amp;sw=f&amp;exact=false" target="_blank" rel="noreferrer">威廉 (William)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=james&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">詹姆斯 (James)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=george&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">乔治 (George)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=joseph&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">约瑟夫 (Joseph)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=michael&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">迈克尔 (Michael)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=thomas&amp;sw=f&amp;exact=false" target="_blank" rel="noreferrer">托马斯 (Thomas)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=david&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">大卫 (David)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=frank&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">弗兰克 (Frank)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=henry&amp;sw=f&amp;exact=true" target="_blank" rel="noreferrer">亨利 (Henry)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=mary&amp;sw=m&amp;exact=false" target="_blank" rel="noreferrer">玛丽 (Mary)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=elizabeth&amp;sw=m&amp;exact=false" target="_blank" rel="noreferrer">伊丽莎白 (Elizabeth)</a>、<a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=sarah&amp;sw=m&amp;exact=true" target="_blank" rel="noreferrer">莎拉 (Sarah)</a> 和 <a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=margaret&amp;sw=m&amp;exact=false" target="_blank" rel="noreferrer">玛格丽特 (Margaret)</a>。</p><p><a href="https://3.bp.blogspot.com/-qbA3n64Yeso/UqgSRw9pZZI/AAAAAAAAGkw/phk07V0ibzw/s1600/gender+handshake.png" target="_blank" rel="noreferrer"><img src="'+J+'" alt=""></a></p><p>而现在,很多最流行的婴儿名字是男女通用的,就好像每个性别都受不了另一个性别搞创新时把自己排除在外。</p><p>我现在真的懂了好多关于名字的事。</p><p>今天就用这道谜题跟你告别吧:</p><h2 id="-1" tabindex="-1"><a href="https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=adolph&amp;sw=both&amp;exact=true" target="_blank" rel="noreferrer"><img src="'+T+'" alt=""></a> <a class="header-anchor" href="#-1" aria-label="Permalink to &quot;[![](/images/how-to-name-baby/adolph.png)](https://www.babynamewizard.com/d3js-voyager/popup.html#prefix=adolph&amp;sw=both&amp;exact=true)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发给你。</p><p>如果想支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。</p><p><strong>______</strong></p><p><strong>如果你喜欢这篇文章,你可能也会喜欢 Wait But Why 的这些文章:</strong></p><p><strong><a href="https://waitbutwhy.com/2014/02/pick-life-partner.html" target="_blank" rel="noreferrer">如何挑选你的人生伴侣</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/06/taming-mammoth-let-peoples-opinions-run-life.html" target="_blank" rel="noreferrer">驯服猛犸象:为什么你该停止在意别人怎么想</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/10/why-procrastinators-procrastinate.html" target="_blank" rel="noreferrer">拖延症患者为什么会拖延</a></strong></p><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2013/12/how-to-name-baby.html&amp;description=How%20to%20Name%20a%20Baby" target="_blank" rel="noreferrer"><img src="'+P+'" alt=""></a></p>',128)])])}const Y=e(E,[["render",R]]);export{F as __pageData,Y as default};
